// Read TASKS.md and extract urgent/important tasks
const fs = require('fs');
const path = '/data/Productivity/TASKS.md';
// NOTE: Replace with actual mounted path

let content = '';
try {
  content = fs.readFileSync(path, 'utf8');
} catch(e) {
  return [{ json: { error: e.message, tasks: [] } }];
}

// Find urgent [!] and important [>] tasks that aren't done [x]
const lines = content.split('\n');
const urgent = [];
const important = [];
const inProgress = [];

lines.forEach(line => {
  const trimmed = line.trim();
  if (trimmed.startsWith('- [x]')) return; // skip done tasks

  if (trimmed.startsWith('- [!]')) {
    const task = trimmed.replace(/^- \[!\]\s*\*\*/, '').replace(/\*\*.*$/, '').trim();
    const full = trimmed.replace(/^- \[!\]\s*/, '').trim();
    urgent.push(full.substring(0, 60));
  } else if (trimmed.startsWith('- [>]')) {
    const full = trimmed.replace(/^- \[>\]\s*/, '').trim();
    important.push(full.substring(0, 60));
  } else if (trimmed.startsWith('- [~]')) {
    const full = trimmed.replace(/^- \[~\]\s*/, '').trim();
    inProgress.push(full.substring(0, 60));
  }
});

// Also check inbox
let inboxCount = 0;
try {
  const inboxPath = path.replace('TASKS.md', 'inbox.md');
  const inbox = fs.readFileSync(inboxPath, 'utf8');
  inboxCount = (inbox.match(/Status: unread/g) || []).length;
} catch(e) {}

const today = new Date().toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' });

return [{
  json: {
    today,
    urgent: urgent.slice(0, 3),
    important: important.slice(0, 3),
    inProgress: inProgress.slice(0, 2),
    inboxCount
  }
}];

// Build the briefing message
const { today, urgent, important, inProgress, inboxCount } = $input.first().json;

let msg = `☀️ *Good morning, Yohan!*\n_${today}_\n\n`;

if (urgent.length > 0) {
  msg += `🔴 *Urgent*\n`;
  urgent.forEach(t => msg += `• ${t}\n`);
  msg += '\n';
}

if (inProgress.length > 0) {
  msg += `🔵 *In Progress*\n`;
  inProgress.forEach(t => msg += `• ${t}\n`);
  msg += '\n';
}

if (important.length > 0) {
  msg += `🟡 *Important*\n`;
  important.forEach(t => msg += `• ${t}\n`);
  msg += '\n';
}

if (inboxCount > 0) {
  msg += `📥 *${inboxCount} unread voice note${inboxCount > 1 ? 's' : ''} in inbox*\n\n`;
}

msg += `_Open dashboard: https://yohan-productivity-dashboard.netlify.app/dashboard.html_`;

return [{ json: { briefing: msg } }];
